{
  "name": "Utah Meals on Wheels",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; program is available regardless of income[6].",
    "asset_limits": "No asset limits mentioned across sources.",
    "other_requirements": ["Homebound (unable to leave home without assistance)[1][5][6][8]", "Unable to shop or prepare meals due to mobility challenges, disability, or frailty[1][2][5][7]", "Resident of the local program's delivery zone or service area (varies by county/PSA)[1][5]", "Do not drive a vehicle (in some areas like Davis County)[5]", "Priority to isolated individuals[6][8]", "Spouses or disabled dependents may qualify in some programs[1][6]", "Under 60 may qualify in limited cases (e.g., disabilities, alternatives clients, or spouses/children with payment)[3][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Nutritious home-delivered midday/lunch meals (hot, one-third daily nutritional needs, low-sodium, heart-healthy; includes protein, vegetables, fruit, grains, milk); 1 meal per delivery day, 5 days/week (Mon-Fri, excluding holidays); optional weekend meals (delivered Thu/Fri in some areas); frequency 1-5 days/week based on need; personal wellness check during delivery[3][5][6][7][8]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (AAA), senior center, or Meals on Wheels provider by phone or online referral[1][2][6]", "Phone examples: Davis County (801-525-5099 implied via site), Utah/Wasatch/Summit Counties (801-229-3802), Cache County (435-755-1720 or 435-755-1722)[5][6][7]", "Online referral (e.g., MAG Utah: magutah.gov/meals/)[6]", "In-person assessment required by staff before starting[6][7]"],
    "processing_time": "Varies; some within a week, others longer due to waitlists; initial assessment after contact[1]",
    "waitlist": "Yes, in some areas (e.g., Utah County since Jan 2022)[6]",
    "forms": ["Nutrition screen (optional, not required to deny meal; may be needed for liquid/medical meals)[3]", "No specific statewide form name; local assessment questions on age, health, mobility, dietary needs, emergency contacts[1]"],
    "documents": ["Proof of age, residence, medical information (for homebound/medical meals); financial docs sometimes but income not always required[1][3]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to delivery zones/service areas within local PSAs/counties; must verify local coverage[1][3]",
    "regional_variations": "Administered locally by AAAs/senior centers with differences in: providers, phone numbers, costs ($3.50-$4 suggested donation/meal, voluntary; $6 for under 60 at centers), weekend meals, waitlists (e.g., Utah County), exact eligibility nuances (e.g., no driving in Davis), delivery frequency[3][5][6][7]",
    "offices_or_providers": ["Davis County Aging Services[5]", "Mountainland Assoc. of Govts (MAG) for Utah/Wasatch/Summit Counties[6]", "Cache County Senior Center[7]", "Local AAAs per region[1][3]"]
  },
  "official_source": "https://rules.utah.gov/publicat/code_rtf/r510-104.rtf (Utah Admin Code R510-104, Aging & Adult Services)",
  "gotchas": ["Must live in specific delivery zone; check local program first[1]", "Homebound strictly assessed/documented annually; able to leave easily or have caregivers may not qualify[1][3][5]", "Suggested donations ($3.50-$4/meal) are voluntary but help expand service; under 60 often pay full[5][6]", "Meals not left if client absent; must cancel by 9am[7]", "Waitlists in high-demand areas like Utah County[6]", "Car ownership may disqualify in some areas[1][5]", "In-person assessment mandatory before starting[6][7]"],
  "data_shape_notes": "Decentralized by county/PSA with local AAAs managing; no statewide income/asset tests; variations in costs, waitlists, exact rules, and providers; homebound + 60+ core but priority to isolated/frail"
}

{
  "name": "Utah Legal Services for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "Income must be at or below 125% of the federal poverty guidelines (e.g., in 2012: $13,613 annually for a 1-person household, $27,938 for a family of four). Exceptions up to 200% allowed if documented economic hardship (e.g., high medical expenses, non-medical disability costs). Exact current dollar amounts vary by year and household size; check current federal poverty guidelines via ULS[3][4].",
    "asset_limits": "Very limited assets required; specific limits not detailed in sources, but financial eligibility considers low assets alongside income[4].",
    "other_requirements": ["Legal issues must relate to senior-specific problems like public benefits (Social Security, SSI, Medicare, Medicaid), adult protective services (abuse, guardianship, powers-of-attorney), housing, consumer issues, living wills[4][5][6]."]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal assistance including counseling, representation, document preparation, and preventive legal presentations on topics like public benefits, housing, consumer issues, Medicare claims, elder abuse, guardianship, powers-of-attorney, wills, estates. Specialized Senior Citizen Law Center staff; volunteer attorneys for wills/estates via Senior Law Project[4][5][6]. No specific dollar amounts or hours stated.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Contact Utah Legal Services (specific intake numbers not listed; call main line or local offices, e.g., Timpanogos Legal Center hotline 801-649-8895 for Utah County[2][9]", "Email: e.g., tlcinfo@timplegal.org for intake forms (TLC example)[2]", "In-person: Clinics like TLC document clinic at Family Justice Center, Utah County (Tuesdays 5-8pm by appointment)[2]", "Website: https://www.utahlegalservices.org/ for general info and contacts[4]"],
    "processing_time": "Not specified; intake screening response sent after form submission (e.g., TLC sets virtual attorney meeting if approved)[2].",
    "waitlist": "Not mentioned; by appointment only for some clinics[2].",
    "forms": ["Intake forms (emailed upon request or filled at clinic)[2]"],
    "documents": ["Proof of income, assets, household size; documentation for exceptions (e.g., medical expenses, benefit denials); case details for screening[3]."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Serves low-income Utahns statewide, with specialized focus on seniors 60+; some contracts county-specific (e.g., Salt Lake County via Senior Citizen Law Center)[5].",
    "regional_variations": "Regional offices/providers (e.g., Salt Lake County Aging and Adult Services contracts with ULS; Utah County options like Timpanogos Legal Center 801-649-8895); potential variation in availability of certified providers or volunteer attorneys[1][2][5][9].",
    "offices_or_providers": ["Utah Legal Services main site; Salt Lake County Senior Citizen Law Center; Timpanogos Legal Center (Utah, Wasatch, Summit Counties)[2][5][9]"]
  },
  "official_source": "https://www.utahlegalservices.org/",
  "gotchas": ["Income up to 200% FPL possible only with Executive Director approval and hardship documentation—don't assume auto-approval[3].", "Not all legal issues covered; must match senior priorities like benefits/housing/abuse[4][6].", "Asset limits are strict and 'very limited'—often overlooked[4].", "Some services via county contracts or volunteers, so availability varies[5].", "Older example figures (2012); always verify current FPL[3][4]."],
  "data_shape_notes": "Income at 125% FPL standard with exceptions to 200%; no fixed asset table or current dollar table in sources (uses annual FPL); senior-specific (60+) with Older Americans Act funding beyond LSC; regional providers and county contracts add variation."
}

{
  "name": "Utah Aging Waiver",
  "eligibility": {
    "age": 65,
    "income_limits": "Single applicant limit is $1,305/month (effective 3/1/25–2/28/26) or $1,330/month (effective March 2026–Feb 2027); limits increase annually in March and apply to individual income with special deductions for living expenses and exemption of spousal income even if living together; almost all income counted[1][2][3].",
    "asset_limits": "Single applicant: $2,000 in countable assets; exempt: primary home (equity under $730,000 if applicant or spouse resides there or intends to return), one automobile (any value), household furnishings/appliances, personal effects/belongings, burial plots/irrevocable burial trusts up to $7,000 each, life insurance face value ≤$1,500; 60-month look-back rule applies with penalty period for transfers below fair market value[1][2][3].",
    "other_requirements": [
      "Utah resident and U.S. citizen or qualified immigrant[2][4].",
      "Nursing Facility Level of Care (NFLOC) determined by RN using InterRAI MDS-HC tool: requires 2 of 3 conditions—significant physical assistance with ≥2 ADLs (toileting, bathing, dressing, transferring, mobility, eating), poor orientation requiring NF care, or medical condition unmet safely without waiver services; dementia diagnosis alone insufficient[1][3][4]."
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Core: case management; other services include personal care, respite/respite care (including LTC facility extension >13 days), adult day care, home modifications/environmental adaptations, specialized medical equipment/supplies/assistive technology (no physician prescription needed for some), non-medical transportation, supplemental meals, personal emergency response systems (PERS) installation/testing/removal/purchase/rental/repair/response, training services, personal budget assistance; no fixed dollar/hour limits specified, tailored via case manager plan of care[4][6].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Phone intake with local Aging & Adult Services office (e.g., Salt Lake County or San Juan County); statewide via Utah Medicaid[4][5].",
      "In-person: local county aging services offices (e.g., San Juan County, Salt Lake County)[4][5]."
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Not mentioned; applications accepted anytime (waiver allows continuous enrollment outside tri-annual periods)[6].",
    "forms": ["No specific form name/number listed; begins with phone intake/assessment by RN/case manager[1][4][5]."],
    "documents": [
      "Proof of income, assets, residency, citizenship/immigration status, medical records/doctor documentation for NFLOC assessment.",
      "Financial details for asset/income verification[1][2][3]."
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide for Utah residents age 65+[2][4].",
    "regional_variations": "Administered via local county aging services (e.g., San Juan County, Salt Lake County) with potential differences in providers/case managers, but core eligibility/benefits uniform[4][5].",
    "offices_or_providers": ["Local Aging & Adult Services offices by county, in partnership with Utah Medicaid[4][5]."]
  },
  "official_source": "https://medicaid.utah.gov (inferred from context; county sites like sanjuancountyut.gov/aging-services and saltlakecounty.gov reference state program)[4][5].",
  "gotchas": [
    "Income limit ~100% FPL but updates March annually (not January like federal); check current effective dates[1][3].",
    "60-month look-back penalty for asset transfers; spousal income exempt even if cohabiting, but separate asset formula[1][4].",
    "NFLOC requires specific ADL/orientation criteria via MDS-HC assessment; dementia alone insufficient[1].",
    "Distinguish from New Choices Waiver (higher income limit $2,901/month, different target group) or ABD Medicaid[2][3]."
  ],
  "data_shape_notes": "Income limits update March annually with special spousal exemptions and separate asset formula; NFLOC via specific MDS-HC tool; services tailored by case management plan without fixed hours/dollars; statewide but county-administered."
}
